      "JjA9Jda2qeK6Tpxk": "Teuflische WiderstandsfÃ¤higkeit: Wuchtschaden",
      "rhUc7IVz5XTphPRp": "Teuflische WiderstandsfÃ¤higkeit: KÃ¤lte",
      "GvzW5wzRBfjFqye7": "Teuflische WiderstandsfÃ¤higkeit: Feuer",
      "UZ00jXoUKfevQhxQ": "Teuflische WiderstandsfÃ¤higkeit: Blitz",
      "iMBfFAs7UwqdgSI5": "Teuflische WiderstandsfÃ¤higkeit: Nekrotisch",
      "G0Ed5szAi1vUFCf7": "Teuflische WiderstandsfÃ¤higkeit: Stichschaden",
